import React, { useState, useContext } from 'react';
import { useNavigate } from 'react-router-dom';
import { AuthContext } from '../context/AuthContext';
import toast from 'react-hot-toast';
import api from '../services/api';

const Login = () => {
  const [formData, setFormData] = useState({ email: '', password: '' });
  const [loading, setLoading] = useState(false);
  const { login } = useContext(AuthContext);
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    
    try {
      const response = await api.post('/auth/login', formData);
      login(response.data);
      
      const { role } = response.data.user;
      toast.success('Welcome to eCMS!');
      
      if (role === 'student') {
        navigate('/student/dashboard');
      } else {
        navigate('/admin/dashboard');
      }
    } catch (error) {
      toast.error(error.response?.data?.message || 'Login failed');
    } finally {
      setLoading(false);
    }
  };

return (
    <div className="flex min-h-screen bg-[#f4f6fb] items-center justify-center p-4">
      <div className="bg-white p-6 rounded-xl shadow-md max-w-md w-full">
        <div className="text-center mb-6">
          <h2 className="text-2xl font-bold text-gray-900">eCMS Portal</h2>
          <p className="text-gray-500">Electronic Certificate Management System</p>
        </div>
        
        <form className="space-y-4" onSubmit={handleSubmit}>
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-2">
              School Email
            </label>
            <input
              type="email"
              required
              className="w-full p-3 border rounded-lg mb-3 focus:ring-2 focus:ring-primary outline-none"
              placeholder="student@xavier.edu.ph"
              value={formData.email}
              onChange={(e) => setFormData({...formData, email: e.target.value})}
            />
          </div>
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-2">
              Password
            </label>
            <input
              type="password"
              required
              className="w-full p-3 border rounded-lg mb-3 focus:ring-2 focus:ring-primary outline-none"
              placeholder="••••••••"
              value={formData.password}
              onChange={(e) => setFormData({...formData, password: e.target.value})}
            />
          </div>

          <button
            type="submit"
            disabled={loading}
            className="w-full bg-primary text-white p-3 rounded-lg hover:opacity-90 transition"
          >
            {loading ? 'Signing in...' : 'Sign In'}
          </button>
        </form>

        <div className="text-center mt-4 pt-4 border-t">
          <p className="text-gray-500 text-sm">Test Accounts:</p>
          <p className="text-gray-400 text-xs mt-1">Student: student1@xavier.edu.ph / password123</p>
          <p className="text-gray-400 text-xs">Admin: admin@xavier.edu.ph / admin123</p>
        </div>
      </div>
    </div>
  );
};

export default Login;
